  "code": "const targetY = args.position.y !== undefined ? args.position.y : Math.floor(bot.entity.position.y);
const wallPositions = [];
for (let h = 0; h < args.height; h++) {
  for (let w = 0; w < args.width; w++) {
    wallPositions.push(new Vec3(args.position.x + w, targetY + h, args.position.z));
  }
}

const findMaterial = function () {
  return bot.inventory.items().find(function (item) {
    return item.name === args.material || item.displayName.toLowerCase().includes(args.material.replace(/_/g, ' '));
  });
};

if (!findMaterial()) {
  return "<MISSING ITEM>: No " + args.material + " found in inventory.";
}

startBackgroundSkill(bot, 'build_wall_2x2', async function (token) {
  const movements = new Movements(bot);
  const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  for (const pos of wallPositions) {
    if (token.cancelled || bot.health <= 0 || !bot.entity) break;

    const existingBlock = bot.blockAt(pos);
    if (existingBlock && existingBlock.name !== 'air') continue;

    const materialItem = findMaterial();
    if (!materialItem) break;

    // Move close enough to place
    bot.pathfinder.setMovements(movements);
    try {
      await bot.pathfinder.goto(new goals.GoalNear(pos.x, pos.y, pos.z, 3));
    } catch (e) {
      // Continue anyway or handle path failure
    }

    if (token.cancelled) break;

    // Find a solid block to place against
    const directions = [
      new Vec3(0, -1, 0),
      new Vec3(0, 0, -1),
      new Vec3(0, 0, 1),
      new Vec3(-1, 0, 0),
      new Vec3(1, 0, 0),
      new Vec3(0, 1, 0)
    ];

    let referenceBlock = null;
    let face = null;

    for (const dir of directions) {
      const neighbor = bot.blockAt(pos.plus(dir));
      if (neighbor && neighbor.name !== 'air') {
        referenceBlock = neighbor;
        face = dir.scaled(-1);
        break;
      }
    }

    if (referenceBlock && face) {
      try {
        await bot.equip(materialItem, 'hand');
        await bot.lookAt(referenceBlock.position.plus(face.scaled(0.5)));
        await bot.placeBlock(referenceBlock, face);
        await sleep(200); 
      } catch (err) {
        console.log("Placement error at " + pos + ": " + err.message);
      }
    }
  }
});

return "<BUILDING>: Started building a " + args.width + "x" + args.height + " wall of " + args.material + " at " + args.position.x + ", " + args.position.z + ".";"
}

