startBackgroundSkill(bot, 'build_2x2_wall', async function(token) {
  const yaw = bot.entity.yaw;
  const forward = new Vec3(-Math.sin(yaw), 0, -Math.cos(yaw));
  const right = new Vec3(-Math.cos(yaw), 0, Math.sin(yaw));

  // Calculate wall start position (2 blocks in front, centered width-wise)
  const startPos = bot.entity.position.add(forward.scaled(2)).floored();
  const lateralOffset = Math.floor(args.width / 2);

  for (let y = 0; y < args.height; y++) {
    for (let x = 0; x < args.width; x++) {
      if (token.cancelled || bot.health <= 0 || !bot.entity) return;

      const targetPos = startPos.add(new Vec3(0, y, 0)).add(right.scaled(x - lateralOffset));

      // Check if block is already filled
      const existingBlock = bot.blockAt(targetPos);
      if (existingBlock && existingBlock.name !== 'air' && existingBlock.name !== 'water' && existingBlock.name !== 'lava') {
        continue;
      }

      // Find a reference block to place against (prefer below, then sides)
      const neighbors = [
        { pos: targetPos.offset(0, -1, 0), face: new Vec3(0, 1, 0) },
        { pos: targetPos.offset(0, 0, 1), face: new Vec3(0, 0, -1) },
        { pos: targetPos.offset(0, 0, -1), face: new Vec3(0, 0, 1) },
        { pos: targetPos.offset(1, 0, 0), face: new Vec3(-1, 0, 0) },
        { pos: targetPos.offset(-1, 0, 0), face: new Vec3(1, 0, 0) }
      ];

      let reference = null;
      for (const n of neighbors) {
        const block = bot.blockAt(n.pos);
        if (block && block.name !== 'air' && block.name !== 'water' && block.name !== 'lava') {
          reference = { block, face: n.face };
          break;
        }
      }

      if (!reference) continue;

      try {
        // Move to reach range if needed
        const movements = new Movements(bot);
        bot.pathfinder.setMovements(movements);
        await bot.pathfinder.goto(new goals.GoalGetToBlock(reference.block.position.x, reference.block.position.y, reference.block.position.z));

        const currentMaterial = findMaterial();
        if (!currentMaterial) return;
        await bot.equip(currentMaterial, 'hand');

        // Face the block and place
        await bot.lookAt(reference.block.position.add(new Vec3(0.5, 0.5, 0.5)));
        await bot.placeBlock(reference.block, reference.face);
      } catch (err) {
        // Ignore placement errors and try next block
      }

      // Small delay between placements
      await new Promise(r => setTimeout(r, 200));
    }
  }
});

return "<BUILDING>: Constructing a " + args.width + "x" + args.height + " wall of " + args.material + " for cover.";"
}

