  "parameters": "z.object({
  maxTargetDist: z.number().default(16).describe("Maximum distance to search for a hostile mob"),
  rangeMode: z.enum(["melee", "ranged"]).default("melee").describe("Whether to use melee attacks or bow/ranged attacks"),
