  },
  "code": "const sleep = function (ms) { return new Promise(resolve => setTimeout(resolve, ms)); };

const isHostile = function (e) {
  if (e.type !== 'mob') return false;
  const hostileNames = ['zombie', 'skeleton', 'creeper', 'spider', 'enderman', 'witch', 'slime', 'husk', 'drowned', 'stray', 'pillager', 'ravager', 'hoglin', 'blaze', 'ghast', 'guardian'];
  return hostileNames.some(function (name) { return e.name && e.name.toLowerCase().includes(name); });
};

const findTarget = function () {
  return Object.values(bot.entities)
    .filter(function (e) { return isHostile(e) && e.position.distanceTo(bot.entity.position) < args.maxTargetDist; })
    .sort(function (a, b) { return bot.entity.position.distanceTo(a.position) - bot.entity.position.distanceTo(b.position); })[0];
};

const weapon = bot.inventory.items().find(function (item) {
  return item.name.includes(args.weaponName.toLowerCase());
});

if (!weapon) {
  return "<NO WEAPON>: Could not find " + args.weaponName + " in inventory.";
}

const target = findTarget();
if (!target) {
  return "<NO TARGET>: No hostile mobs within " + args.maxTargetDist + " blocks.";
}

startBackgroundSkill(bot, 'attack_nearest_hostile', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);

  while (!token.cancelled && bot.health > 0 && bot.entity) {
    if (!bot.physicsEnabled) {
      await sleep(100);
      continue;
    }

    const currentTarget = findTarget();
    if (!currentTarget) {
      console.log('No more hostile targets in range.');
      bot.pathfinder.setGoal(null);
      break;
    }

    const item = bot.inventory.items().find(function (i) { return i.name.includes(args.weaponName.toLowerCase()); });
    if (item) await bot.equip(item, 'hand');

    if (args.rangeMode === 'melee') {
      bot.pathfinder.setGoal(new goals.GoalFollow(currentTarget, 2), true);
      if (bot.entity.position.distanceTo(currentTarget.position) < 3.5) {
        bot.lookAt(currentTarget.position.offset(0, 1, 0));
        bot.attack(currentTarget);
        await sleep(600); // Attack cooldown
      } else {
        await sleep(100);
      }
    } else {
      // Ranged mode
      const arrow = bot.inventory.items().find(function (i) { return i.name.includes('arrow'); });
      if (!arrow) {
        console.log('No arrows found for ranged attack.');
        break;
      }
      bot.lookAt(currentTarget.position.offset(0, 1.5, 0));
      bot.activateItem();
      await sleep(1200); // Charge bow
      bot.deactivateItem();
      await sleep(200);
    }
  }
});

return "<ATTACKING>: Engaged closest target: " + target.name + " (ID: " + target.id + ") using " + args.rangeMode + " mode.";"
}

