  return value.trim().toLowerCase().replace(/^minecraft:/, '').replace(/\s+/g, '_');
};
const requestedName = normalizeItemName(args.itemName);
const itemToDrop = bot.inventory.items().find(function (item) {
  const internalNameMatch = normalizeItemName(item.name) === requestedName;
  const displayNameMatch = typeof item.displayName === 'string' && normalizeItemName(item.displayName) === requestedName;
  return internalNameMatch || displayNameMatch;
});
if (!itemToDrop) {
  return "<NO ITEM>: Could not find " + args.itemName + " in my inventory.";
}
const amountToDrop = Math.min(args.count, itemToDrop.count);
try {
  await bot.toss(itemToDrop.type, itemToDrop.metadata || null, amountToDrop);
  const nameUsed = itemToDrop.displayName || itemToDrop.name;
  return "<DROPPED>: Successfully dropped " + amountToDrop + " " + nameUsed + " at my current position.";
} catch (error) {
  return "<ERROR>: Failed to drop " + args.itemName + ": " + error.message;
}"
